<?php
namespace Tests\Feature\Hr;use Illuminate\Support\Facades\Artisan;use Illuminate\Support\Facades\Schema;use Tests\TestCase;
class HrPhase6ACompensationRollbackTest extends TestCase{use RefreshHrDatabase;public function test_compensation_schema_exists():void{$this->assertTrue(Schema::hasColumns('hr_salary_records',['version','gross_salary_encrypted','approved_by']));$this->assertTrue(Schema::hasTable('hr_salary_bands'));$this->assertTrue(Schema::hasTable('hr_benefits'));$this->assertTrue(Schema::hasTable('hr_employee_benefits'));}public function test_rollback_preserves_lifecycle():void{Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);$this->assertFalse(Schema::hasTable('hr_salary_records'));$this->assertTrue(Schema::hasTable('hr_onboarding_checklists'));$this->assertTrue(Schema::hasTable('hr_job_postings'));}}
